import 'package:flutter/material.dart';\nimport 'admin_dashboard.dart';\nimport 'infrastructure_management.dart';\nimport 'map_monitoring.dart';\nimport 'alerts_management.dart';\n\nclass Analytics extends StatelessWidget {\n  @override\n  Widget build(BuildContext context) {\n    return Scaffold(\n      appBar: AppBar(\n        title: Text('Analytics'),\n        backgroundColor: Colors.red,\n      ),\n      endDrawer: _buildNavDrawer(context),\n      body: ListView(\n        padding: EdgeInsets.all(16),\n        children: [\n          Row(\n            children: [\n              _buildMetricCard('Total Assets', '105', Icons.location_city, Colors.blue),\n              _buildMetricCard('Active Alerts', '22', Icons.warning, Colors.red),\n            ],\n          ),\n          SizedBox(height: 16),\n          Row(\n            children: [\n              _buildMetricCard('Avg Utilization', '73%', Icons.trending_up, Colors.green),\n              _buildMetricCard('Maintenance Due', '8', Icons.build, Colors.orange),\n            ],\n          ),\n          SizedBox(height: 24),\n          Card(\n            child: Padding(\n              padding: EdgeInsets.all(16),\n              child: Column(\n                crossAxisAlignment: CrossAxisAlignment.start,\n                children: [\n                  Text('Usage Trends', style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),\n                  SizedBox(height: 16),\n                  Container(\n                    height: 200,\n                    color: Colors.grey[200],\n                    child: Center(\n                      child: Text('Chart Placeholder', style: TextStyle(color: Colors.grey[600])),\n                    ),\n                  ),\n                ],\n              ),\n            ),\n          ),\n        ],\n      ),\n    );\n  }\n\n  Widget _buildMetricCard(String title, String value, IconData icon, Color color) {\n    return Expanded(\n      child: Card(\n        child: Padding(\n          padding: EdgeInsets.all(16),\n          child: Column(\n            children: [\n              Icon(icon, size: 32, color: color),\n              SizedBox(height: 8),\n              Text(value, style: TextStyle(fontSize: 24, fontWeight: FontWeight.bold, color: color)),\n              Text(title, style: TextStyle(fontSize: 12)),\n            ],\n          ),\n        ),\n      ),\n    );\n  }\n\n  Widget _buildNavDrawer(BuildContext context) {\n    return Drawer(\n      child: ListView(\n        children: [\n          DrawerHeader(\n            decoration: BoxDecoration(color: Colors.red),\n            child: Text('Admin Menu', style: TextStyle(color: Colors.white, fontSize: 24)),\n          ),\n          ListTile(\n            leading: Icon(Icons.dashboard),\n            title: Text('Dashboard'),\n            onTap: () => Navigator.push(context, MaterialPageRoute(builder: (context) => AdminDashboard())),\n          ),\n          ListTile(\n            leading: Icon(Icons.build),\n            title: Text('Infrastructure'),\n            onTap: () => Navigator.push(context, MaterialPageRoute(builder: (context) => InfrastructureManagement())),\n          ),\n          ListTile(\n            leading: Icon(Icons.map),\n            title: Text('Map Monitoring'),\n            onTap: () => Navigator.push(context, MaterialPageRoute(builder: (context) => MapMonitoring())),\n          ),\n          ListTile(\n            leading: Icon(Icons.warning),\n            title: Text('Alerts'),\n            onTap: () => Navigator.push(context, MaterialPageRoute(builder: (context) => AlertsManagement())),\n          ),\n          ListTile(\n            leading: Icon(Icons.analytics),\n            title: Text('Analytics'),\n            onTap: () => Navigator.pop(context),\n          ),\n        ],\n      ),\n    );\n  }\n}